"""GET/POST /api/settings — runtime-adjustable bot parameters."""
from __future__ import annotations

from fastapi import APIRouter, HTTPException
from pydantic import BaseModel

from bot.ledger import repo

router = APIRouter()

_ALLOWED_KEYS = {
    "base_trade_usd",
    "roster_active_size",
    "roster_standby_size",
    "stop_loss_enabled",
}


class SettingUpdate(BaseModel):
    key: str
    value: str


@router.get("")
async def get_settings_store() -> dict:
    return await repo.get_all_settings()


@router.post("")
async def update_setting(body: SettingUpdate) -> dict:
    if body.key not in _ALLOWED_KEYS:
        raise HTTPException(status_code=400, detail=f"Key '{body.key}' is not adjustable at runtime")
    await repo.set_setting(body.key, body.value)
    return {"key": body.key, "value": body.value}

