const BASE = process.env.NEXT_PUBLIC_API_URL ?? "http://127.0.0.1:8787";

async function get<T>(path: string): Promise<T> {
  const res = await fetch(`${BASE}${path}`, { cache: "no-store" });
  if (!res.ok) throw new Error(`${res.status} ${path}`);
  return res.json();
}

async function post<T>(path: string, body: unknown): Promise<T> {
  const res = await fetch(`${BASE}${path}`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });
  if (!res.ok) throw new Error(`${res.status} ${path}`);
  return res.json();
}

export const api = {
  getState: () => get<BotState>("/api/state"),
  getOpenPositions: () => get<Position[]>("/api/positions/open"),
  getClosedPositions: () => get<Position[]>("/api/positions/closed"),
  getPnlCurve: () => get<EquityPoint[]>("/api/positions/pnl"),
  getLeaders: () => get<Leader[]>("/api/leaders"),
  getLeader: (proxy: string) => get<LeaderDetail>(`/api/leaders/${proxy}`),
  getSettings: () => get<Record<string, string>>("/api/settings"),
  updateSetting: (key: string, value: string) => post("/api/settings", { key, value }),
  triggerKillSwitch: (reason: string) => post("/api/kill-switch", { action: "trigger", reason }),
  resetKillSwitch: () => post("/api/kill-switch", { action: "reset" }),
};

