"use client";

import { useEffect, useRef, useState } from "react";
import { eventBus, WsEvent } from "@/lib/ws";

type LogEntry = {
  ts: string;
  type: string;
  payload: Record<string, unknown>;
  id: number;
};

const TYPE_COLORS: Record<string, string> = {
  SIGNAL: "#6366f1",
  FILL: "#10b981",
  REJECT: "#ef4444",
  EXIT: "#f59e0b",
  KILL_SWITCH: "#ef4444",
  DISCOVERY: "#60a5fa",
  RECOVERY: "#f59e0b",
  HEARTBEAT: "#334155",
};

function colorFor(type: string) {
  return TYPE_COLORS[type] ?? "#94a3b8";
}

let _id = 0;

export default function LogsPage() {
  const [logs, setLogs] = useState<LogEntry[]>([]);
  const [paused, setPaused] = useState(false);
  const [filter, setFilter] = useState("");
  const [selectedType, setSelectedType] = useState<string>("ALL");
  const bottomRef = useRef<HTMLDivElement>(null);
  const pausedRef = useRef(false);

  useEffect(() => { pausedRef.current = paused; }, [paused]);

  useEffect(() => {
    return eventBus.subscribe((ev: WsEvent) => {
      if (pausedRef.current) return;
      const entry: LogEntry = {
        ts: new Date(ev.ts * 1000).toISOString().replace("T", " ").slice(0, 23),
        type: ev.type,
        payload: ev.payload as Record<string, unknown>,
        id: ++_id,
      };
      setLogs(prev => [entry, ...prev].slice(0, 500));
    });
  }, []);

  useEffect(() => {
    if (!paused) bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [logs, paused]);

  const types = ["ALL", ...Array.from(new Set(logs.map(l => l.type))).sort()];
  const filtered = logs.filter(l => {
    if (selectedType !== "ALL" && l.type !== selectedType) return false;
    if (filter && !JSON.stringify(l).toLowerCase().includes(filter.toLowerCase())) return false;
    return true;
  });

  return (
    <div style={{ display: "flex", flexDirection: "column", height: "calc(100vh - 96px)", gap: 12 }}>
      <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
        <h1 style={{ fontSize: 18, fontWeight: 700, color: "#e2e8f0" }}>Live Logs</h1>
        <span style={{
          width: 8, height: 8, borderRadius: "50%",
          background: paused ? "#ef4444" : "#10b981",
          boxShadow: paused ? "none" : "0 0 6px #10b981",
          flexShrink: 0,
        }} />
        <span style={{ color: "#64748b", fontSize: 11 }}>{paused ? "PAUSED" : "LIVE"}</span>
        <div style={{ flex: 1 }} />

        <input
          value={filter}
          onChange={e => setFilter(e.target.value)}
          placeholder="Filter…"
          style={{
            background: "#111118", border: "1px solid #1e2030", borderRadius: 4,
            color: "#e2e8f0", padding: "4px 10px", fontSize: 11, width: 160,
            outline: "none",
          }}
        />

        <select
          value={selectedType}
          onChange={e => setSelectedType(e.target.value)}
          style={{
            background: "#111118", border: "1px solid #1e2030", borderRadius: 4,
            color: "#e2e8f0", padding: "4px 8px", fontSize: 11, outline: "none",
          }}
        >
          {types.map(t => <option key={t} value={t}>{t}</option>)}
        </select>

        <button
          onClick={() => setPaused(p => !p)}
          style={{
            background: paused ? "#1a2e1a" : "#2a1a1a",
            border: `1px solid ${paused ? "#10b981" : "#ef4444"}`,
            color: paused ? "#10b981" : "#ef4444",
            borderRadius: 4, padding: "4px 12px", fontSize: 11, cursor: "pointer",
          }}
        >
          {paused ? "Resume" : "Pause"}
        </button>

        <button
          onClick={() => setLogs([])}
          style={{
            background: "#1e2030", border: "1px solid #334155",
            color: "#94a3b8", borderRadius: 4, padding: "4px 12px", fontSize: 11, cursor: "pointer",
          }}
        >
          Clear
        </button>
      </div>

      <div className="card" style={{
        flex: 1, overflow: "auto", padding: 0, fontFamily: "monospace",
      }}>
        {filtered.length === 0 ? (
          <div style={{ padding: 32, color: "#64748b", fontSize: 12 }}>
            {logs.length === 0 ? "Waiting for events from the bot…" : "No entries match filter"}
          </div>
        ) : (
          <div style={{ display: "flex", flexDirection: "column-reverse" }}>
            {filtered.map(entry => (
              <div key={entry.id} style={{
                display: "flex", gap: 12, padding: "4px 12px",
                borderBottom: "1px solid #0d0d14", fontSize: 11, alignItems: "flex-start",
              }}
                onMouseEnter={e => (e.currentTarget.style.background = "#13131f")}
                onMouseLeave={e => (e.currentTarget.style.background = "transparent")}
              >
                <span style={{ color: "#334155", flexShrink: 0 }}>{entry.ts}</span>
                <span style={{
                  color: colorFor(entry.type),
                  fontWeight: 700, flexShrink: 0, width: 100,
                }}>
                  {entry.type}
                </span>
                <span style={{ color: "#94a3b8", wordBreak: "break-all" }}>
                  {Object.entries(entry.payload)
                    .filter(([k]) => k !== "ts")
                    .map(([k, v]) => `${k}=${typeof v === "number" ? (Number.isInteger(v) ? v : (v as number).toFixed(4)) : String(v)}`)
                    .join("  ")}
                </span>
              </div>
            ))}
            <div ref={bottomRef} />
          </div>
        )}
      </div>

      <div style={{ fontSize: 11, color: "#64748b" }}>
        {filtered.length} entries shown · {logs.length} total buffered (max 500)
      </div>
    </div>
  );
}

