const BASE = process.env.NEXT_PUBLIC_API_URL ?? "http://127.0.0.1:8787";

async function get<T>(path: string): Promise<T> {
  const res = await fetch(`${BASE}${path}`, { cache: "no-store" });
  if (!res.ok) throw new Error(`${res.status} ${path}`);
  return res.json();
}

async function post<T>(path: string, body: unknown): Promise<T> {
  const res = await fetch(`${BASE}${path}`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });
  if (!res.ok) throw new Error(`${res.status} ${path}`);
  return res.json();
}

export const api = {
  getState: () => get<BotState>("/api/state"),
  getOpenPositions: () => get<Position[]>("/api/positions/open"),
  getClosedPositions: () => get<Position[]>("/api/positions/closed"),
  getPnlCurve: () => get<EquityPoint[]>("/api/positions/pnl"),
  getLeaders: () => get<Leader[]>("/api/leaders"),
  getLeader: (proxy: string) => get<LeaderDetail>(`/api/leaders/${proxy}`),
  getSettings: () => get<Record<string, string>>("/api/settings"),
  updateSetting: (key: string, value: string) => post("/api/settings", { key, value }),
  triggerKillSwitch: (reason: string) => post("/api/kill-switch", { action: "trigger", reason }),
  resetKillSwitch: () => post("/api/kill-switch", { action: "reset" }),
};

export interface BotState {
  mode: string;
  kill_switch_triggered: boolean;
  kill_switch_reason: string | null;
  equity_usd: number;
  cash_usd: number;
  open_positions_usd: number;
  realized_pnl_usd: number;
  unrealized_pnl_usd: number;
  total_trades: number;
  win_rate: number;
  paper_gate_passed: boolean;
  daily_loss_usd: number;
  fill_rate: number;
}

export interface Position {
  id: number;
  condition_id: string;
  token_id: string;
  outcome: string;
  shares: number;
  cost_usd: number;
  avg_entry_price: number;
  opened_at_ts: number;
  closed_at_ts?: number;
  is_open: boolean;
  realized_pnl?: number;
  exit_reason?: string;
}

export interface EquityPoint {
  ts: number;
  equity: number;
  cash: number;
  positions: number;
}

export interface Leader {
  proxy_address: string;
  rank: number;
  tier: string;
  score: number;
  score_delta: number;
  status: string;
  snapshot_date: string;
}

export interface LeaderDetail {
  leader: Leader;
  recent_signals: Signal[];
}

export interface Signal {
  id: string;
  detected_at: number;
  condition_id: string;
  side: string;
  leader_price: number;
  leader_size: number;
  status: string;
}

