"""GET/POST /api/settings — runtime-adjustable bot parameters."""
from __future__ import annotations

from fastapi import APIRouter, HTTPException
from pydantic import BaseModel

from bot.ledger import repo

router = APIRouter()

_ALLOWED_KEYS = {
    "base_trade_usd",
    "roster_active_size",
    "roster_standby_size",
    "stop_loss_enabled",
}


class SettingUpdate(BaseModel):
    key: str
    value: str


@router.get("")
async def get_settings_store() -> dict:
    return await repo.get_all_settings()


@router.post("")
async def update_setting(body: SettingUpdate) -> dict:
    if body.key not in _ALLOWED_KEYS:
        raise HTTPException(status_code=400, detail=f"Key '{body.key}' is not adjustable at runtime")
    await repo.set_setting(body.key, body.value)
    return {"key": body.key, "value": body.value}

"""POST /api/kill-switch — manual trigger and reset."""
from __future__ import annotations

from fastapi import APIRouter, HTTPException
from pydantic import BaseModel

from bot.ledger import repo
from bot.observability.log import get_logger

log = get_logger(__name__)
router = APIRouter()


class KillSwitchAction(BaseModel):
    action: str  # "trigger" or "reset"
    reason: str = "manual"


@router.get("")
async def get_kill_switch() -> dict:
    return await repo.get_kill_switch()


@router.post("")
async def set_kill_switch(body: KillSwitchAction) -> dict:
    if body.action == "trigger":
        await repo.trigger_kill_switch(reason=body.reason)
        log.warning("kill_switch_manual_trigger", reason=body.reason)
        return {"triggered": True, "reason": body.reason}
    elif body.action == "reset":
        await repo.reset_kill_switch()
        log.info("kill_switch_manual_reset")
        return {"triggered": False, "reason": None}
    else:
        raise HTTPException(status_code=400, detail="action must be 'trigger' or 'reset'")

